mapper.select:
SELECT MIN(EXER_SEQ) AS exerSeq, USER_UUID AS userUuid, EXER_DATE AS exerDate, EXER_STIME AS exerStime, MAX(EXER_ETIME) AS exerEtime, CONCAT(CASE WHEN HOUR(MAX(REG_DTTM)) < 12 THEN '오전' ELSE '오후' END, ' ', DATE_FORMAT(MAX(REG_DTTM), '%h:%i')) AS regDtm, GROUP_CONCAT(EXER_NAME SEPARATOR ', ') AS exerName, SUM(IFNULL(EXER_CNT,0)) AS totalCnt, COUNT(*) AS rowCnt FROM T_EXER_TRAN WHERE USER_UUID = #{userUuid}
AND EXER_DATE = #{exerDate}
GROUP BY USER_UUID, EXER_DATE, EXER_STIME ORDER BY EXER_DATE DESC, EXER_STIME DESC

mapper.delete:
DELETE
FROM T_EXER_TRAN
WHERE USER_UUID = #{userUuid}
  AND EXER_DATE = #{exerDate}
  AND EXER_STIME = #{exerStime}
